import { useEffect, useState } from "react";
import api from "../../api/axios";
import { useNavigate } from "react-router-dom";

export default function LeadList() {
  const [leads, setLeads] = useState([]);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const load = async () => {
    setLoading(true);
    try {
      const res = await api.get("/leads");
      setLeads(res.data || []);
    } catch (err) {
      alert(err.response?.data?.message || "Failed to load leads");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, []);

  const onDelete = async (id, name) => {
    if (!window.confirm(`Delete lead "${name}"?`)) return;

    try {
      await api.delete(`/leads/${id}`);
      setLeads((prev) => prev.filter((l) => l._id !== id));
      alert("Lead deleted");
    } catch (err) {
      alert(err.response?.data?.message || "Delete failed");
    }
  };

  return (
    <div style={{ padding: 20 }}>
      <h2>Leads</h2>

      <button onClick={() => navigate("/leads/add")}>+ Add Lead</button>
      <button onClick={load} style={{ marginLeft: 8 }} disabled={loading}>
        {loading ? "Loading..." : "Refresh"}
      </button>

      <table border="1" cellPadding="8" style={{ marginTop: 15, width: "100%" }}>
        <thead>
          <tr>
            <th>Name</th>
            <th>Contact</th>
            <th>Email</th>
            <th>Source</th>
            <th>Interest</th>
            <th>Status</th>
            <th style={{ width: 180 }}>Actions</th>
          </tr>
        </thead>
        <tbody>
          {leads.map((lead) => (
            <tr key={lead._id}>
              <td>{lead.name}</td>
              <td>{lead.contact_number}</td>
              <td>{lead.email}</td>
              <td>{lead.lead_source}</td>
              <td>{lead.interest_level}</td>
              <td>{lead.status}</td>
              <td>
                <button onClick={() => navigate(`/leads/edit/${lead._id}`)}>
                  Edit
                </button>

                <button
                  onClick={() => onDelete(lead._id, lead.name)}
                  style={{ marginLeft: 8 }}
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}

          {leads.length === 0 && !loading && (
            <tr>
              <td colSpan="7">No leads found</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}
